class Solution:
    def minOrAfterOperations(self, nums, k):
        n = len(nums)
        best = None
        for boundary_mask in range(1 << (n - 1)):
            merges_used = (n - 1) - bin(boundary_mask).count('1')
            if merges_used > k:
                continue
            segments = []
            cur = nums[0]
            for i in range(n - 1):
                if (boundary_mask >> i) & 1:
                    segments.append(cur)
                    cur = nums[i + 1]
                else:
                    cur &= nums[i + 1]
            segments.append(cur)
            orv = 0
            for s in segments:
                orv |= s
            if best is None or orv < best:
                best = orv
        return best

