class Solution:
    def minOrAfterOperations(self, nums, k):
        n = len(nums)
        FULL = (1 << 30) - 1
        def feasible(x):
            segments = 0
            cur = FULL
            for v in nums:
                cur &= v
                if (cur & ~x) & FULL == 0:
                    segments += 1
                    cur = FULL
            return segments >= n - k
        answer = 0
        for bit in range(29, -1, -1):
            candidate = answer | ((1 << bit) - 1)
            if not feasible(candidate):
                answer |= (1 << bit)
        return answer

