var minOrAfterOperations = function(nums, k) {
    const n = nums.length;
    const FULL = (1 << 30) - 1;
    function feasible(x) {
        let segments = 0;
        let cur = FULL;
        for (const v of nums) {
            cur &= v;
            if ((cur & ~x & FULL) === 0) {
                segments++;
                cur = FULL;
            }
        }
        return segments >= n - k;
    }
    let answer = 0;
    for (let bit = 29; bit >= 0; bit--) {
        const candidate = answer | ((1 << bit) - 1);
        if (!feasible(candidate)) {
            answer |= (1 << bit);
        }
    }
    return answer >>> 0;
};
